// Script Continued Below
// RJ - OU REQUEST TYPE
function onSubmit() {

	var table;
	var RequestSysId; 
	var modalForm;
	var title;
	var view;
	var ou_parent;
	var query;
	var formAction = g_form.getActionName();

	// STRY0088787 added if statement to check the submit is a Request submit, then doing save before continuing
	// each form acction needs to be above save confirmation below or it never gets to any other logic and stays in a confirmation loop
	if(formAction == 'request_organizational_update'  ||
	   formAction == 'create_sub_ou' || 
	   formAction == 'add_member_to_ou' || 
	   formAction == 'add_contact_to_ou') {
		// each button needs to be added 
		if(!saveConfirmation())
			return false;

		ou_parent = g_form.getUniqueValue();

		// TESTING RETURN AFTER SAVE CONFIRMATION FOR NOW
		if(formAction == 'create_sub_ou'){
			// TODO - multilanguage - NOTE: what is done on new here should be done in Tasker Form with Tabs and other places
			open_New_Modal('x_153465_discovert_discover_office_hierarchy', getMessage('New Sub OU'), view, 'parent=' + ou_parent);
		} else if(formAction == 'add_member_to_ou'){
			// TODO - multilanguage - NOTE: what is done on new here should be done in Tasker Form with Tabs and other places
			open_New_Modal('x_153465_discovert_discover_office_members', getMessage('New OU Member'), view, 'discover_office_hierarchy=' + ou_parent);
		} else if(formAction == 'add_contact_to_ou'){
			// TODO - multilanguage - NOTE: what is done on new here should be done in Tasker Form with Tabs and other places
			open_New_Modal('x_153465_discovert_organizational_contacts', getMessage('New OU Contact'), view, 'u_contact_ou=' + ou_parent);

		} else if(formAction == 'request_organizational_update'){
			if(!g_scratchpad.OUHA_responsible.GlobalAdministrators.value && !g_scratchpad.OUHA_responsible.Administrators.value){
				// no people are available to send request, raise error
				g_form.addErrorMessage(getMessage('Tasker - There are no available Hierarchy Administrators. Please contact your Application Administrator to add Hierarchy Administrators.'));
				return false;
			}
			open_New_Modal('x_153465_discovert_tasker_requests', getMessage('Tasker - Title - Request Hierarchy Update'), 'ou_requesttop', 'u_ou_parent=' + ou_parent);


		}
		return false;
	}

	// this is called from the Open Modal callback to refresh the form
	function refreshForm() {
		g_form.save();
	}	

	function open_New_Modal(table, title, view, query) {
		if (typeof spModal != 'undefined' ) { 
			spModal.open({
				title: title,
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {
					table: table,
					sys_id: "-1",
					view: view,
					query: query,
					// DFCT0010643
					omitHeader: 'true',
					// STRY0040294 - added isModal - added closing of open modal
					isModal: true //,
				},
				size: 'lg',
				buttons: [],
				// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
				footerStyle: {
					'display': 'none'
				}
			});
		} else {
			modalForm = new GlideModalForm(title, table);
			modalForm.addParm('sysparm_query',query);
			modalForm.addParm('sysparm_view', view); //Specify a form view
			modalForm.render();
			modalForm.setSysID(-1);
			modalForm.setCompletionCallback(refreshForm);
		}
	}

	// NOTE this code exists in too many places, need to understand how to move into a client script library
	function saveConfirmation(){
		var saveConfirmed = true;
		var saveMsg =  getMessage('Tasker - Modal Save Changes Message');
		if(typeof spModal != 'undefined'){
			var fMsg = '';
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				// start as true, if no changes it will return true, if changes confirmation will have to set back to true
				saveConfirmed = false;
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				fMsg = changeFieldList.join(', ');
				spModal.confirm(saveMsg + "  "+ fMsg).then(function(confirmed) {
					g_form.save();
					saveConfirmed = true;
				});
			}
		} else if (typeof spModal == 'undefined' && g_form.modified) {
			// start as true, if no changes it will return true, if changes confirmation will have to set back to true
			saveConfirmed = false;
			saveMsg += JSON.stringify(g_form.modifiedFields);
			if(confirm(saveMsg)){
				g_form.save();
				saveConfirmed = true;				
			} else{
				return saveConfirmed;
			}			
		}

		return saveConfirmed;
	}	
}
